def _sort_palette(self, sort_palette):
    """
    Reorders this image's palette according to ``sort_palette``, which
    may be ``"rgb"``, ``"luminance"`` or a callable. See
    :py:meth:`~PIL.Image.Image.quantize` for details.
    """
    channels = len(self.palette.mode)
    palette = self.palette.palette
    num_colors = len(palette) // channels
    colors = [
        tuple(palette[i * channels : i * channels + channels])
        for i in range(num_colors)
    ]

    if sort_palette == "rgb":
        key = lambda i: colors[i]  # noqa: E731
    elif sort_palette == "luminance":
        key = lambda i: (  # noqa: E731
            colors[i][0] * 299 + colors[i][1] * 587 + colors[i][2] * 114
        )
    elif callable(sort_palette):
        key = lambda i: sort_palette(colors[i])  # noqa: E731
    else:
        msg = "sort_palette must be 'rgb', 'luminance' or a callable"
        raise ValueError(msg)

    order = sorted(range(num_colors), key=key)
    return self.remap_palette(order)

